package com.securestack.config;import org.springframework.context.annotation.*;import org.springframework.security.config.annotation.web.builders.HttpSecurity;import org.springframework.security.web.SecurityFilterChain;import org.springframework.web.cors.*;import java.util.*;@Configuration public class SecurityConfig{@Bean SecurityFilterChain filter(HttpSecurity h)throws Exception{return h.csrf(c->c.disable()).cors(c->{ }).authorizeHttpRequests(a->a.anyRequest().permitAll()).build();}@Bean CorsConfigurationSource corsConfigurationSource(){CorsConfiguration c=new CorsConfiguration();c.setAllowedOriginPatterns(List.of("http://localhost:*"));c.setAllowedMethods(List.of("GET","POST","PATCH","DELETE","OPTIONS"));c.setAllowedHeaders(List.of("*"));UrlBasedCorsConfigurationSource s=new UrlBasedCorsConfigurationSource();s.registerCorsConfiguration("/**",c);return s;}}
